hooks.command:
node -e "
const fs=require('fs');
const input=JSON.parse(require('fs').readFileSync('/dev/stdin','utf8'));
const content=input.tool_input?.content||input.tool_input?.new_string||'';
const patterns=[
  /sk-ant-[a-zA-Z0-9\-_]{20,}/,
  /sk-[a-zA-Z0-9]{48,}/,
  /AKIA[0-9A-Z]{16}/,
  /ghp_[a-zA-Z0-9]{36}/,
  /AIza[0-9A-Za-z\-_]{35}/,
  /-----BEGIN (RSA |OPENSSH )?PRIVATE KEY-----/,
  /(postgres|mysql|mongodb):(\/\/)[^:]+:[^@]+@/
];
const found=patterns.find(p=>p.test(content));
if(found){
  console.error('aiguard: обнаружен секрет в записываемом файле — операция заблокирована.');
  process.exit(2);
}
"
